import { Routes, Route } from "react-router-dom";

import Login from "../pages/Auth/Login";
import Register from "../pages/Auth/Register";
import DashboardPage from "../pages/Admin/DashboardPage";
import Home from "../pages/Home/HomePage";
import CourseDetailPage from "../pages/Course/CourseDetailPage";
import MainLayout from "../layouts/MainLayout";
import AuthLayout from "../layouts/AuthLayout";
import ProtectedRoute from "../utils/ProtectedRoute";
import LessonPage from "../pages/Lesson/LessonPage";
import CheckoutPage from "../pages/Payment/CheckoutPage";
import MyCoursesPage from "../pages/Payment/MyCoursesPage";
import AssignmentListPage from "../pages/Assignment/AssignmentListPage";
import SubmitAssignmentPage from "../pages/Assignment/SubmitAssignmentPage";
const AppRoutes = () => {
  return (
    <Routes>

      {/* AUTH */}
      <Route element={<AuthLayout />}>
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
      </Route>

      {/* MAIN */}
      <Route path="/" element={<MainLayout />}>
        <Route index element={<Home />} />
      </Route>
      <Route path="/courses/:id" element={<CourseDetailPage />} />

      {/* LESSON PAGE */}
      <Route
        path="/courses/:courseId/lessons"
        element={
          <ProtectedRoute role={["ADMIN", "INSTRUCTOR"]}>
            <LessonPage />
          </ProtectedRoute>
        }
      />
      {/* CHECKOUT PAGE */}
      <Route
  path="/checkout/:courseId"
  element={
    <ProtectedRoute role="STUDENT">
      <CheckoutPage />
    </ProtectedRoute>
  }
/>
<Route
  path="/my-courses"
  element={
    <ProtectedRoute role="STUDENT">
      <MyCoursesPage />
    </ProtectedRoute>
  }
/>
<Route 
  path="/courses/:courseId/assignments" 
  element={<AssignmentListPage />} 
/>
<Route 
  path="/assignments/:assignmentId/submit" 
  element={<SubmitAssignmentPage />} 
/>
      {/* ADMIN */}
      <Route
        path="/admin"
        element={
          <ProtectedRoute role="ADMIN">
            <DashboardPage />
          </ProtectedRoute>
        }
      />

      {/* FALLBACK */}
      <Route path="*" element={<div>404 NOT FOUND</div>} />

    </Routes>
  );
};

export default AppRoutes;
